public async Task<bool> PurchaseTicketsAsync(int eventId, int quantityRequested, int userId)
{
    using (var context = new BookingContext())
    {
        var eventEntity = await context.Events
            .Include(e => e.Seats)
            .SingleOrDefaultAsync(e => e.EventId == eventId);

        if (eventEntity == null || eventEntity.SeatsAvailable < quantityRequested)
            return false;

        try
        {
            eventEntity.SeatsAvailable -= quantityRequested;
            context.Entry(eventEntity).State = EntityState.Modified;

            var purchase = new TicketPurchase
            {
                UserId = userId,
                EventId = eventId,
                Quantity = quantityRequested,
                PurchaseDate = DateTime.UtcNow
            };

            await context.TicketPurchases.AddAsync(purchase);
            await context.SaveChangesAsync();
        }
        catch (DbUpdateConcurrencyException)
        {
            return false; // Handle the concurrent update case
        }

        return true;
    }
}